let cart=[],currentGrade="dealer",filteredProducts=[...ALL_PRODUCTS],selectedIndustry=null;
const fmt=n=>Math.round(n).toLocaleString("ko-KR");
const getP=p=>{const g=currentGrade==="dealer"?"dealer":currentGrade==="oem"?"oem":"endUser";const mk=currentGrade==="enduser"?"enduser":g;const cfg=(window.MK_SETTINGS&&window.MK_SETTINGS.multipliers)||{dealer:100,oem:100,enduser:100};const adj=(window.MK_QUOTE_ADJUST==null?100:window.MK_QUOTE_ADJUST);return Math.round(p[g]*(cfg[mk]||100)/100*adj/100);};

function renderIndustries(){
  document.getElementById("industryGrid").innerHTML=INDUSTRIES.map(i=>`<div class="industry-card${selectedIndustry===i.id?" selected":""}" onclick="selectIndustry('${i.id}')"><div class="ind-icon">${i.icon}</div><div class="ind-name">${i.name}</div><div class="ind-proc">${i.process.slice(0,32)}...</div></div>`).join("");
}

function selectIndustry(id){
  selectedIndustry=id;renderIndustries();
  const ind=INDUSTRIES.find(i=>i.id===id);
  document.getElementById("processDetail").style.display="block";
  document.getElementById("processInfo").innerHTML=`<h3>${ind.icon} ${ind.name}</h3><p><strong>주요 공정:</strong> ${ind.process}</p><p style="margin-top:6px">${ind.keyPoint}</p><p style="margin-top:6px;font-size:12px;color:#888">${ind.recommend}</p><div style="font-size:11px;font-weight:600;color:#888;text-transform:uppercase;letter-spacing:0.05em;margin:10px 0 6px">권장 모델</div><div class="model-tags">${ind.kw.map(k=>`<span class="model-tag">${k}</span>`).join("")}</div><div style="font-size:12px;color:#888;margin-top:8px">진공도: <span class="vbadge">${ind.vacuum}</span> &nbsp; 펌프: <span class="vbadge">${ind.pumpType}</span></div>`;
  renderRec(ind);
}

function renderRec(ind){
  const kws=ind.kw.map(k=>k.toLowerCase());
  const matches=ALL_PRODUCTS.filter(p=>{const d=p.description.toLowerCase(),n=p.partNo.toLowerCase();return kws.some(k=>d.includes(k)||n.includes(k));}).slice(0,25);
  const tbody=document.getElementById("recResults");
  if(!matches.length){tbody.innerHTML=`<tr><td colspan="4" class="no-match">매칭 품목 없음 — 검색탭에서 직접 검색해주세요.</td></tr>`;return;}
  tbody.innerHTML=matches.map(p=>`<tr><td><span class="partno">${p.partNo}</span><br><span class="sheet-tag">${p.sheet.replace("2026 Price_","")}</span></td><td>${p.description}</td><td class="price-cell">${fmt(getP(p))}원</td><td><button class="add-btn" onclick="addProduct('${p.partNo}',this)">담기 +</button></td></tr>`).join("");
}

function doSearch(){
  const q=document.getElementById("searchInput").value.toLowerCase();
  const s=document.getElementById("sheetFilter").value;
  filteredProducts=ALL_PRODUCTS.filter(p=>(!q||p.partNo.toLowerCase().includes(q)||p.description.toLowerCase().includes(q))&&(!s||p.sheet===s));
  document.getElementById("resultCount").textContent=`${filteredProducts.length}개 품목 (최대 100개 표시)`;
  document.getElementById("searchResults").innerHTML=filteredProducts.slice(0,100).map(p=>{
    return `<tr>
      <td class="col-no" style="color:#aaa;font-size:11px">${p.no}</td>
      <td class="col-part"><span class="partno">${p.partNo}</span><br><span class="sheet-tag">${p.sheet.replace("2026 Price_","")}</span><div class="m-price">${fmt(p.endUser)}원 <span class="m-price-tag">원가</span></div><div class="m-desc">${p.description}</div></td>
      <td class="col-desc" style="max-width:280px">${p.description}</td>
      <td class="col-dealer price-cell">${fmt(p.dealer)}</td>
      <td class="col-oem price-cell">${fmt(p.oem)}</td>
      <td class="col-enduser price-cell">${fmt(p.endUser)}</td>
      <td class="col-add"><button class="add-btn" onclick="addProduct('${p.partNo}',this)">담기 +</button></td>
    </tr>`;
  }).join("");
}

function addProduct(partNo,btn){
  const p=ALL_PRODUCTS.find(x=>x.partNo===partNo);if(!p)return;
  const ex=cart.find(c=>c.partNo===partNo);
  if(ex)ex.qty++;else cart.push({...p,qty:1,customPrice:null});
  renderCart();
  const total=cart.reduce((s,i)=>s+i.qty,0);
  document.getElementById("cartCount").textContent=total;
  if(btn){
    btn.textContent="담김 ✓";btn.classList.add("added");
    setTimeout(()=>{btn.textContent="담기 +";btn.classList.remove("added");},900);
  }
  if(window.mkToast) window.mkToast(`${p.partNo} 담김 · 총 ${total}건`,"ok");
}

function renderCart(){
  const empty=document.getElementById("cartEmpty"),wrap=document.getElementById("cartWrap"),totals=document.getElementById("cartTotals");
  if(!cart.length){empty.style.display="block";wrap.style.display="none";totals.style.display="none";return;}
  empty.style.display="none";wrap.style.display="block";totals.style.display="block";
  document.getElementById("cartBody").innerHTML=cart.map((item,i)=>{
    const base=getP(item),price=item.customPrice!==null?item.customPrice:base;
    return`<tr><td><span class="partno">${item.partNo}</span></td><td>${item.description}</td><td style="text-align:center"><input class="qty-input" type="number" value="${item.qty}" min="1" onchange="updateQty(${i},this.value)"></td><td style="text-align:right"><input class="price-edit" type="text" value="${fmt(price)}" onchange="setPrice(${i},this.value)" title="단가 직접 수정 가능"></td><td class="price-cell">${fmt(price*item.qty)}</td><td><button class="del-btn" onclick="del(${i})">삭제</button></td></tr>`;
  }).join("");
  const sub=cart.reduce((s,item)=>{const p=item.customPrice!==null?item.customPrice:getP(item);return s+p*item.qty;},0);
  const vat=Math.round(sub*0.1);
  document.getElementById("subtotal").textContent=fmt(sub)+"원";
  document.getElementById("vat").textContent=fmt(vat)+"원";
  document.getElementById("grandTotal").textContent=fmt(sub+vat)+"원";
  if(window.updateFloatCta) window.updateFloatCta();
}

function updateQty(i,v){cart[i].qty=Math.max(1,parseInt(v)||1);renderCart();document.getElementById("cartCount").textContent=cart.reduce((s,i)=>s+i.qty,0);}
function del(i){cart.splice(i,1);renderCart();document.getElementById("cartCount").textContent=cart.reduce((s,i)=>s+i.qty,0);}
function setPrice(i,v){const n=parseInt(v.replace(/[^0-9]/g,""));cart[i].customPrice=isNaN(n)?null:n;renderCart();}

function setGrade(g){
  const prev=currentGrade;
  if(prev!==g && cart.length>0){
    if(!confirm(`등급을 변경하면 장바구니 ${cart.length}건의 단가가 모두 재계산됩니다. 계속하시겠습니까?`)) return;
  }
  currentGrade=g;
  try{ localStorage.setItem("mk.lastGrade",g); }catch(e){}
  const map={dealer:"gradeDealer",oem:"gradeOEM",enduser:"gradeEndUser"};
  Object.entries(map).forEach(([k,id])=>{const el=document.getElementById(id);if(el)el.classList.toggle("selected",k===g);});
  renderCart();
  if(selectedIndustry){const ind=INDUSTRIES.find(i=>i.id===selectedIndustry);if(ind)renderRec(ind);}
}

document.getElementById("deliveryWeeks").addEventListener("input",function(){document.getElementById("deliveryDays").textContent=this.value*7;});

const qDate=()=>{const n=new Date();return`${String(n.getFullYear()).slice(2)}${String(n.getMonth()+1).padStart(2,"0")}${String(n.getDate()).padStart(2,"0")}_SR01`;};

function switchTab(t){
  document.querySelectorAll(".tab").forEach(el=>el.classList.toggle("active",el.dataset.tab===t));
  document.querySelectorAll(".bn-btn").forEach(el=>el.classList.toggle("active",el.dataset.tab===t));
  document.querySelectorAll(".panel").forEach(el=>el.classList.toggle("active",el.id==="tab-"+t));
  const active = document.querySelector(`.tab[data-tab="${t}"]`);
  const lbl = document.getElementById("ttLabel");
  if(active && lbl) lbl.textContent = active.textContent.replace(/\s*\d+\s*$/,"").trim();
  toggleTabMenu(false);
  window.scrollTo(0,0);
  if(window.MK_ON_TAB)window.MK_ON_TAB(t);
}

function toggleTabMenu(force){
  const tabs = document.getElementById("tabsEl");
  const back = document.getElementById("tabBackdrop");
  const trig = document.getElementById("tabTrigger");
  if(!tabs) return;
  const open = (force===undefined) ? !tabs.classList.contains("open") : !!force;
  tabs.classList.toggle("open", open);
  if(back) back.classList.toggle("open", open);
  if(trig) trig.setAttribute("aria-expanded", String(open));
}

function goPreview(){
  if(!cart.length){
    if(window.mkToast) window.mkToast("먼저 품목을 담아주세요","warn"); else alert("먼저 품목을 담아주세요.");
    switchTab("search"); return;
  }
  const cn=document.getElementById("customerName").value.trim();
  if(!cn){
    const ok=confirm("수신처(회사명)가 비어 있습니다. 그래도 계속할까요?");
    if(!ok){ switchTab("quote"); setTimeout(()=>document.getElementById("customerName").focus(),150); return; }
  }
  renderPreview();switchTab("preview");
  if(window.MK_ARCHIVE_SAVE)window.MK_ARCHIVE_SAVE();
}
