function copyText(){navigator.clipboard.writeText(document.getElementById("previewContent").innerText).then(()=>alert("견적서 내용이 클립보드에 복사되었습니다."));}

// ---------- 토스트 유틸 ----------
window.mkToast = function(msg, kind){
  const el = document.getElementById("mkToast");
  if(!el) return;
  el.textContent = msg;
  el.className = "mk-toast show" + (kind ? " "+kind : "");
  clearTimeout(window._mkToastT);
  window._mkToastT = setTimeout(()=>{ el.classList.remove("show"); }, 2200);
};

// ---------- 모바일 플로팅 CTA ----------
window.updateFloatCta = function(){
  const cta = document.getElementById("floatCta");
  const count = cart.reduce((s,i)=>s+i.qty,0);
  const ttCount = document.getElementById("ttCount");
  if(ttCount){
    if(count>0){ ttCount.textContent = count+"건"; ttCount.style.display = ""; }
    else{ ttCount.style.display = "none"; }
  }
  const bnBadge = document.getElementById("bnBadge");
  if(bnBadge){
    if(count>0){ bnBadge.textContent = count; bnBadge.style.display = ""; }
    else{ bnBadge.style.display = "none"; }
  }
  if(!cta) return;
  if(count === 0){
    cta.classList.remove("active");
    document.body.classList.remove("has-cta");
    return;
  }
  const sub = cart.reduce((s,i)=>{const p=i.customPrice!==null?i.customPrice:getP(i);return s+p*i.qty;},0);
  const grand = sub + Math.round(sub*0.1);
  document.getElementById("fcCount").textContent = count+"건";
  document.getElementById("fcTotal").textContent = "₩"+fmt(grand);
  cta.classList.add("active");
  document.body.classList.add("has-cta");
};

