try{
  const lg = localStorage.getItem("mk.lastGrade");
  if(lg && ["dealer","oem","enduser"].includes(lg)){
    currentGrade = lg;
    const map={dealer:"gradeDealer",oem:"gradeOEM",enduser:"gradeEndUser"};
    Object.entries(map).forEach(([k,id])=>{const el=document.getElementById(id);if(el)el.classList.toggle("selected",k===lg);});
  }
}catch(e){}

